-- ============================================
-- STEP 1: DELETE ALL DUMMY/MOCK WORKERS
-- ============================================
DELETE FROM workers;

-- ============================================
-- STEP 2: INSERT 54 REAL WORKERS FROM JAGTIAL
-- ============================================

-- ============================================
-- STEP 3: VERIFY — check counts per category
-- ============================================
SELECT c.name, COUNT(w.id) as worker_count
FROM categories c
LEFT JOIN workers w ON w.category_id = c.id AND w.is_approved = true
GROUP BY c.name ORDER BY c.name;